// app/api/health/route.ts
import { NextResponse } from 'next/server';

export async function GET() {
  const checks: Record<string, 'ok' | 'error'> = {};
  let healthy = true;

  // Database check
  try {
    await pool.query('SELECT 1');
    checks.database = 'ok';
  } catch {
    checks.database = 'error';
    healthy = false;
  }

  // External API check
  try {
    const res = await fetch('https://api.example.com/ping', { signal: AbortSignal.timeout(3000) });
    checks.externalApi = res.ok ? 'ok' : 'error';
  } catch {
    checks.externalApi = 'error';
  }

  return NextResponse.json({
    status: healthy ? 'healthy' : 'degraded',
    version: process.env.APP_VERSION ?? '1.0.0',
    uptime: process.uptime(),
    checks,
    timestamp: new Date().toISOString(),
  }, { status: healthy ? 200 : 503 });
}

// lib/logger.ts
type LogLevel = 'debug' | 'info' | 'warn' | 'error';

const LOG_LEVELS: Record<LogLevel, number> = { debug: 0, info: 1, warn: 2, error: 3 };
const MIN_LEVEL = LOG_LEVELS[(process.env.LOG_LEVEL as LogLevel) ?? 'info'];

function log(level: LogLevel, message: string, meta?: Record<string, unknown>) {
  if (LOG_LEVELS[level] < MIN_LEVEL) return;

  const entry = {
    timestamp: new Date().toISOString(),
    level,
    message,
    ...meta,
  };

  if (process.env.NODE_ENV === 'production') {
    console[level === 'error' ? 'error' : 'log'](JSON.stringify(entry));
  } else {
    console[level === 'error' ? 'error' : 'log'](`[${level.toUpperCase()}] ${message}`, meta ?? '');
  }
}

export const logger = {
  debug: (msg: string, meta?: Record<string, unknown>) => log('debug', msg, meta),
  info: (msg: string, meta?: Record<string, unknown>) => log('info', msg, meta),
  warn: (msg: string, meta?: Record<string, unknown>) => log('warn', msg, meta),
  error: (msg: string, meta?: Record<string, unknown>) => log('error', msg, meta),
};
